class Solution:
    def sortVowels(self, s: str) -> str:
        vowels = []
        # First pass: collect vowels and note their positions
        vowel_indices = []
        for i, char in enumerate(s):
            if char.lower() in {'a', 'e', 'i', 'o', 'u'}:
                vowels.append(char)
                vowel_indices.append(i)

        # Sort vowels by their ASCII values
        vowels.sort()

        # Second pass: build the result string
        result = list(s)
        for idx, pos in enumerate(vowel_indices):
            result[pos] = vowels[idx]

        return ''.join(result)
